if (!$json.body?.products || !Array.isArray($json.body.products)) {
  throw new Error('❌ Nenhum produto no payload');
}
if (!$json.body?.integrations || !Array.isArray($json.body.integrations) || $json.body.integrations.length === 0) {
  throw new Error('❌ Nenhuma integração no payload');
}

const products = $json.body.products;
const integrations = $json.body.integrations;

console.log('✅ Produtos:', products.length);
console.log('✅ Integrações:', integrations.length);

return {
  chatId: $json.chatId || null,
  timestamp: $json.timestamp || Date.now(),
  products: products,
  integrations: integrations
};

const products = $json.products;
const integrations = $json.integrations;

const items = [];

for (const product of products) {
  for (const integration of integrations) {
    items.push({
      json: {
        product: product,
        integrationId: integration.id,
        integrationName: integration.name,
        integrationToken: integration.token
      }
    });
  }
}

console.log('📦 Total:', items.length);
return items;

const p = $json.product;
const integrationId = $json.integrationId;
const integrationName = $json.integrationName;
const integrationToken = $json.integrationToken;

let variacoes = null;
if (p.variacoes && Array.isArray(p.variacoes) && p.variacoes.length > 0) {
  variacoes = p.variacoes;
}

return {
  nome: p.nome || '',
  codigo: p.codigo || '',
  preco: parseFloat(p.preco) || 0,
  tipo: p.tipo || 'P',
  situacao: p.situacao || 'A',
  formato: p.formato || (variacoes ? 'V' : 'S'),
  unidade: p.unidade || 'UN',
  pesoLiquido: parseFloat(p.pesoLiquido) || 0,
  pesoBruto: parseFloat(p.pesoBruto) || 0,
  marca: p.marca || '',
  linkExterno: p.linkExterno || '',
  altura: parseFloat(p.altura) || 0,
  largura: parseFloat(p.largura) || 0,
  profundidade: parseFloat(p.profundidade) || 0,
  variacoes: variacoes,
  hasVariations: variacoes !== null,
  integrationId: integrationId,
  integrationName: integrationName,
  integrationToken: integrationToken
};

const p = $json;

if (!p.variacoes || !Array.isArray(p.variacoes) || p.variacoes.length === 0) {
  throw new Error('❌ Sem variações');
}

// ✅ EXTRAIR TIPOS DE VARIAÇÃO
const tiposVariacao = new Set();
p.variacoes.forEach(v => {
  const variacaoNome = v.variacao?.nome;
  if (variacaoNome) {
    const parts = variacaoNome.split(';');
    parts.forEach(part => {
      const [tipo] = part.split(':');
      if (tipo) tiposVariacao.add(tipo.trim());
    });
  }
});

const primeiroTipo = Array.from(tiposVariacao)[0] || 'Tamanho';

const variacoesArray = p.variacoes.map(v => {
  return {
    id: 0,
    codigo: v.codigo || `${p.codigo}-VAR`,
    preco: parseFloat(v.preco) || parseFloat(p.preco) || 0,
    tipo: "P",
    situacao: "A",
    formato: "S",
    unidade: v.unidade || p.unidade || "UN",
    pesoLiquido: parseFloat(v.pesoLiquido) || parseFloat(p.pesoLiquido) || 0,
    pesoBruto: parseFloat(v.pesoBruto) || parseFloat(p.pesoBruto) || 0,
    dimensoes: {
      largura: parseFloat(v.dimensoes?.largura) || parseFloat(p.largura) || 0,
      altura: parseFloat(v.dimensoes?.altura) || parseFloat(p.altura) || 0,
      profundidade: parseFloat(v.dimensoes?.profundidade) || parseFloat(p.profundidade) || 0,
      unidadeMedida: 1
    },
    midia: {
      imagens: {
        externas: v.midia?.imagens?.externas || []
      }
    },
    variacao: {
      nome: v.variacao?.nome || '',
      produtoPai: {
        cloneInfo: true
      }
    }
  };
});

const productBody = {
  nome: p.nome,
  codigo: p.codigo,
  tipo: "P",
  situacao: "A",
  formato: "V",
  variacao: {
    nome: primeiroTipo.charAt(0).toUpperCase() + primeiroTipo.slice(1)
  },
  variacoes: variacoesArray
};

console.log('📦 Produto:', p.nome);
console.log('🔢 Variações:', variacoesArray.length);
console.log('🏷️ Tipo variação:', primeiroTipo);

return {
  productBody: productBody,
  productCode: p.codigo,
  productName: p.nome,
  integrationId: p.integrationId,
  integrationName: p.integrationName,
  integrationToken: p.integrationToken
};

const p = $json;

const productBody = {
  nome: p.nome,
  codigo: p.codigo,
  preco: p.preco,
  tipo: p.tipo,
  situacao: p.situacao,
  formato: "S",
  unidade: p.unidade,
  pesoLiquido: p.pesoLiquido,
  pesoBruto: p.pesoBruto,
  dimensoes: {
    largura: p.largura,
    altura: p.altura,
    profundidade: p.profundidade,
    unidadeMedida: 1
  },
  ...(p.marca && { marca: p.marca }),
  ...(p.linkExterno && { linkExterno: p.linkExterno })
};

return {
  productBody: productBody,
  productCode: p.codigo,
  productName: p.nome,
  integrationId: p.integrationId,
  integrationName: p.integrationName,
  integrationToken: p.integrationToken
};

const allData = $input.item.json;

// Extrai resposta do Bling
let blingResponse = allData;

if (typeof blingResponse === 'string') {
  try {
    blingResponse = JSON.parse(blingResponse);
  } catch (e) {
    console.error('❌ Parse error:', e.message);
  }
}

if (Array.isArray(blingResponse) && blingResponse.length > 0) {
  blingResponse = blingResponse[0];
}

// RECUPERA METADADOS QUE FORAM GUARDADOS NO NÓ SET
const productCode = allData._productCode || 'N/A';
const productName = allData._productName || 'N/A';
const integrationId = allData._integrationId || null;
const integrationName = allData._integrationName || 'Desconhecida';

let status = 'erro';
let message = 'Erro desconhecido';
let blingId = null;
let variationsSaved = 0;

console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
console.log('🔍 PRODUTO:', productName);
console.log('📦 Código:', productCode);
console.log('🔗 Integração:', integrationName);

try {
  if (blingResponse && blingResponse.data && blingResponse.data.id) {
    status = 'sucesso';
    blingId = blingResponse.data.id;
    message = 'Produto cadastrado';

    if (blingResponse.data.variations?.saved) {
      variationsSaved = blingResponse.data.variations.saved.length;
      if (variationsSaved > 0) {
        message = `Produto com ${variationsSaved} variação(ões)`;
      }
    }

    console.log('✅ SUCESSO! ID:', blingId);
  }
  else if (blingResponse && blingResponse.error) {
    message = blingResponse.error.message || 'Erro';

    if (blingResponse.error.type === 'validation' && blingResponse.error.fields) {
      const fieldErrors = [];

      blingResponse.error.fields.forEach(field => {
        if (field.code === 4) status = 'duplicado';

        if (field.collection && Array.isArray(field.collection)) {
          field.collection.forEach(varError => {
            if (varError.collection) {
              varError.collection.forEach(err => {
                if (err.code === 4) status = 'duplicado';
                fieldErrors.push(`[Var ${varError.index + 1}] ${err.msg}`);
              });
            }
          });
        } else if (field.msg) {
          fieldErrors.push(field.msg);
        }
      });

      if (fieldErrors.length > 0) message = fieldErrors.join(' | ');
    }

    const msgLower = message.toLowerCase();
    if (msgLower.includes('já existe') || msgLower.includes('duplicado')) {
      status = 'duplicado';
    }

    console.log('⚠️', status.toUpperCase());
  }
  else if (allData.statusCode && allData.statusCode >= 400) {
    message = `HTTP ${allData.statusCode}`;
    console.log('❌ ERROR');
  }
  else {
    message = 'Resposta inesperada';
    console.log('⚠️ RESPOSTA INESPERADA');
  }
} catch (e) {
  status = 'erro';
  message = `Exceção: ${e.message}`;
  console.error('💥', e.message);
}

console.log('📌', status.toUpperCase());
console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n');

return {
  status: status,
  productCode: productCode,
  productName: productName,
  blingId: blingId,
  variationsSaved: variationsSaved,
  message: message,
  integrationId: integrationId,
  integrationName: integrationName,
  timestamp: new Date().toISOString()
};

// ============================================
// CRIAR RELATÓRIO - CORRIGIDO
// ============================================
// Cole este código no nó "Criar Relatório"

const items = $input.all();

let sucessos = 0;
let erros = 0;
let duplicados = 0;
const detalhes = [];
const sucessosLista = [];
const duplicadosLista = [];
const errosLista = [];
const porIntegracao = {};

items.forEach(item => {
  // ===== CORREÇÃO: Extrai dados corretamente =====
  let d = item.json;

  // Se os dados estiverem dentro de "data", extrai
  if (d.data && Array.isArray(d.data) && d.data.length > 0) {
    d = d.data[0];
  }

  console.log('📦 Processando item:', d.productName || 'N/A', '| Status:', d.status);

  if (!porIntegracao[d.integrationName]) {
    porIntegracao[d.integrationName] = { sucessos: 0, erros: 0, duplicados: 0 };
  }

  const detalhe = {
    codigo: d.productCode,
    nome: d.productName,
    status: d.status,
    blingId: d.blingId,
    variationsSaved: d.variationsSaved || 0,
    mensagem: d.message,
    integrationName: d.integrationName
  };

  if (d.status === 'sucesso') {
    sucessos++;
    porIntegracao[d.integrationName].sucessos++;
    sucessosLista.push(detalhe);
  } else if (d.status === 'duplicado') {
    duplicados++;
    porIntegracao[d.integrationName].duplicados++;
    duplicadosLista.push(detalhe);
  } else {
    erros++;
    porIntegracao[d.integrationName].erros++;
    errosLista.push(detalhe);
  }
  detalhes.push(detalhe);
});

const total = items.length;
const taxaSucesso = total > 0 ? ((sucessos / total) * 100).toFixed(2) : '0.00';

console.log('\n╔═══════════════════════════════════╗');
console.log('║      📊 RELATÓRIO FINAL           ║');
console.log('╚═══════════════════════════════════╝');
console.log('✅ Sucessos:', sucessos);
console.log('🔄 Duplicados:', duplicados);
console.log('❌ Erros:', erros);
console.log('📈 Taxa de sucesso:', taxaSucesso + '%\n');

return {
  success: erros === 0,
  timestamp: new Date().toISOString(),
  resumo: {
    total: total,
    totalIntegracoes: Object.keys(porIntegracao).length,
    totalEnvios: total,
    sucessos: sucessos,
    duplicados: duplicados,
    erros: erros,
    taxaSucesso: `${taxaSucesso}%`
  },
  detalhes: {
    todos: detalhes,
    sucessos: sucessosLista,
    duplicados: duplicadosLista,
    erros: errosLista,
    porIntegracao: porIntegracao
  }
};
